                let update = new Set();
                for(let postfix of parse(expresion, i)) {
                    for(let prefix of current) {
                        update.add(prefix + postfix);
                    }
                }
                current = update;
            } else if (c === '}') {
                break;
            } else if (c === ',') {
                for(let cur of current) {
                    result.add(cur);
                }
                current.clear();
                current.add("");
            } else {
                let update = new Set();
                for(let element of current) {
                    update.add(element + c);
                }
                current = update;
            }
        }

        for(let cur of current) {
            result.add(cur);
        }
        return result;
    }

    const i = [0];
    return Array.from(parse(expression, i)).sort();
};
