solutionCode.java:
    ```java
import java.util.*;

class Solution {
    public List<String> braceExpansionII(String expression) {
        int[] i = new int[]{0};
        Set<String> parsedSet = parse(expression, i);
        List<String> result = new ArrayList<>(parsedSet);
        Collections.sort(result);
        return result;
    }

    private Set<String> parse(String expression, int[] i) {
        HashSet<String> current = new HashSet<>();
        current.add("");
        HashSet<String> result = new HashSet<>();

        while (i[0] < expression.length()) {
            char c = expression.charAt(i[0]++);
            if (c == '{') {
                HashSet<String> temp = new HashSet<>();
                for (String postfix : parse(expression, i)) {
                    for (String prefix : current) {
                        temp.add(prefix + postfix);
                    }
                }
                current = temp;
            } else if (c == '}') {
                break;
            } else if (c == ',') {
                result.addAll(current);
                current.clear();
                current.add("");
            } else {
                HashSet<String> temp = new HashSet<>();
                for (String s : current) {
                    temp.add(s + c);
                }
                current = temp;
            }
        }
        result.addAll(current);
        return result;
    }
}
```

